pragma solidity ^0.8.4;

contract Token {
    string public name;
    string public symbol;
    uint8 public decimals = 18;
    uint256 public totalSupply;
    address public owner;
    bool public tradingOpen;
    bool public swappingEnabled;

    struct Fee {
        uint256 buyFee;
        uint256 sellFee;
    }

    mapping(address => uint256) public balances;
    mapping(address => mapping(address => uint256)) public allowances;
    mapping(address => Fee) public fees;
    address public devAddress;
    address public marketingAddress;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(
        string memory _name,
        string memory _symbol,
        uint256 _totalSupply,
        address _devAddress,
        address _marketingAddress
    ) {
        name = _name;
        symbol = _symbol;
        totalSupply = _totalSupply * 10**decimals;
        balances[msg.sender] = totalSupply;
        owner = msg.sender;
        devAddress = _devAddress;
        marketingAddress = _marketingAddress;
        tradingOpen = false;
        swappingEnabled = false;
    }

    function transfer(address recipient, uint256 amount) external returns (bool) {
        require(tradingOpen, "Trading is not open");
        require(balances[msg.sender] >= amount, "Insufficient balance");

        if (!swappingEnabled) {
            require(recipient != address(0), "Invalid recipient");
        }

        uint256 feeAmount;
        if (msg.sender == devAddress || msg.sender == marketingAddress) {
            feeAmount = 0;
        } else {
            Fee memory fee = fees[recipient];
            if (recipient == devAddress || recipient == marketingAddress) {
                feeAmount = (amount * fee.sellFee) / 10000;
            } else {
                feeAmount = (amount * fee.buyFee) / 10000;
            }
        }

        uint256 transferAmount = amount - feeAmount;
        balances[msg.sender] -= amount;
        balances[recipient] += transferAmount;
        balances[devAddress] += feeAmount / 2;
        balances[marketingAddress] += feeAmount / 2;

        emit Transfer(msg.sender, recipient, transferAmount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function swapTokens() external onlyOwner {
        require(swappingEnabled, "Swapping is not enabled");
        // Implement token swapping logic here
    }

    function openTrading() external onlyOwner {
        tradingOpen = true;
    }

    function closeTrading() external onlyOwner {
        tradingOpen = false;
    }

    function enableSwapping() external onlyOwner {
        swappingEnabled = true;
    }

    function disableSwapping() external onlyOwner {
        swappingEnabled = false;
    }

    function setFees(address _address, uint256 _buyFee, uint256 _sellFee) external onlyOwner {
        fees[_address] = Fee(_buyFee, _sellFee);
    }

    function getBalance(address _address) external view returns (uint256) {
        return balances[_address];
    }

    function getAllowance(address _owner, address _spender) external view returns (uint256) {
        return allowances[_owner][_spender];
    }
}
