        symbol = _symbol;
        totalSupply = _totalSupply * 10**decimals;
        accounts[msg.sender].balance = totalSupply;
        owner = msg.sender;
        devAddress = _devAddress;
        marketingAddress = _marketingAddress;
        tradingOpen = false;
        swappingEnabled = false;
        currentState = State.TradingClosed;
    }

