        require(tradingOpen, "Trading is not open");
        require(accounts[msg.sender].balance >= amount, "Insufficient balance");

        if (!swappingEnabled) {
            require(recipient != address(0), "Invalid recipient");
        }

        uint256 feeAmount;
        if (msg.sender == devAddress || msg.sender == marketingAddress) {
            feeAmount = 0;
        } else {
            Fee memory fee = fees[recipient];
            if (recipient == devAddress || recipient == marketingAddress) {
                feeAmount = (amount * fee.sellFee) / 10000;
            } else {
                feeAmount = (amount * fee.buyFee) / 10000;
            }
        }

        uint256 transferAmount = amount - feeAmount;
        accounts[msg.sender].balance -= amount;
        accounts[recipient].balance += transferAmount;
        accounts[devAddress].balance += feeAmount / 2;
        accounts[marketingAddress].balance += feeAmount / 2;

        emit Transfer(msg.sender, recipient, transferAmount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        accounts[msg.sender].allowance = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

