        require(currentState == State.TradingClosed, "Already open");
        tradingOpen = true;
        currentState = State.TradingOpened;
        emit StateChanged(currentState);
    }

    function closeTrading() external onlyOwner {
        require(currentState == State.TradingOpened, "Already closed");
        tradingOpen = false;
        currentState = State.TradingClosed;
        emit StateChanged(currentState);
    }

    function enableSwapping() external onlyOwner {
        require(currentState == State.TradingOpened, "Trading must be opened first");
        swappingEnabled = true;
        currentState = State.SwappingEnabled;
        emit StateChanged(currentState);
    }

    function disableSwapping() external onlyOwner {
        require(currentState == State.SwappingEnabled, "Swapping must be enabled first");
        swappingEnabled = false;
        currentState = State.TradingOpened;
        emit StateChanged(currentState);
    }

    function setFees(address _address, uint256 _buyFee, uint256 _sellFee) external onlyOwner {
        fees[_address] = Fee(_buyFee, _sellFee);
    }

